<style>
:root{--bg:#050505;--panel:#0b0b0d;--line:rgba(255,255,255,.13);--text:#fff;--muted:#aaa;--red:#e7332f;--red2:#ff4b45;--green:#25d366}*{box-sizing:border-box}body{margin:0;min-height:100vh;font-family:Arial,Helvetica,sans-serif;color:var(--text);background:radial-gradient(circle at 50% 0,rgba(231,51,47,.16),transparent 35%),linear-gradient(180deg,#070707,#010101);padding:0 14px 26px}button,input,textarea,select{font:inherit}button{cursor:pointer}.shell{width:min(1480px,100%);margin:auto}.nav{height:72px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--line);gap:16px}.brand{display:flex;align-items:center;gap:12px;font-weight:900;letter-spacing:2px;text-transform:uppercase}.logo{display:grid;place-items:center;width:42px;height:42px;border:1px solid rgba(231,51,47,.65);color:var(--red2);font-size:24px}.nav-links{display:flex;gap:26px;color:#d8d8d8;font-size:13px;font-weight:800;text-transform:uppercase}.top-zap,.zap{border:1px solid rgba(231,51,47,.75);background:linear-gradient(180deg,rgba(231,51,47,.26),rgba(231,51,47,.08));color:#fff;text-decoration:none;border-radius:8px;padding:13px 18px;font-weight:900;text-transform:uppercase}.hero{display:grid;grid-template-columns:minmax(0,1fr)420px;gap:22px;margin-top:22px}.stage,.side-card,.regions,.foot-card{background:linear-gradient(180deg,rgba(18,18,20,.92),rgba(5,5,6,.96));border:1px solid var(--line);border-radius:14px;box-shadow:0 26px 80px rgba(0,0,0,.42)}.stage{padding:22px;min-width:0}.heading{display:flex;align-items:start;justify-content:space-between;gap:16px;margin-bottom:16px}h1{margin:0;font-size:clamp(30px,4vw,52px);line-height:.95;text-transform:uppercase}.lead{margin:8px 0 0;color:#ddd;line-height:1.45}.tip{display:flex;gap:12px;align-items:center;padding:12px 14px;border:1px solid var(--line);border-radius:8px;color:#ddd;background:rgba(255,255,255,.04);max-width:270px}.tip b{font-size:25px;color:var(--red2)}.segmented{display:inline-flex;border:1px solid var(--line);border-radius:8px;overflow:hidden;margin:8px 0 18px;background:#090909}.segmented button{border:0;background:transparent;color:#ddd;padding:13px 22px;font-weight:900;text-transform:uppercase}.segmented button.active{background:linear-gradient(180deg,var(--red),#7b1111);color:#fff;box-shadow:0 0 18px rgba(231,51,47,.35)}.maps{display:grid;place-items:center;min-height:670px}.map-box{position:relative;width:min(100%,560px);height:670px;border-radius:12px;background:radial-gradient(circle at 50% 45%,rgba(231,51,47,.12),transparent 40%),#050505;overflow:hidden}.map-box.hidden{display:none}.body-render{position:absolute;left:50%;top:50%;height:94%;max-width:74%;transform:translate(-50%,-50%);object-fit:contain;filter:drop-shadow(0 26px 38px rgba(0,0,0,.9));user-select:none;pointer-events:none}.hotspot{position:absolute;border:1px solid rgba(255,82,72,.52);background:rgba(231,51,47,.05);border-radius:999px;color:transparent;transition:.16s;z-index:2}.hotspot:hover,.hotspot.focused{background:rgba(231,51,47,.24);border-color:#ff756d;box-shadow:0 0 22px rgba(255,75,69,.8)}.hotspot.selected{background:rgba(231,51,47,.5);border-color:#fff;box-shadow:0 0 28px rgba(255,75,69,1)}.legend{display:flex;align-items:center;justify-content:center;gap:20px;margin:12px 0 0;color:#ddd;font-size:13px}.dot{display:inline-block;width:13px;height:13px;border-radius:50%;border:1px solid #fff;margin-right:7px}.dot.sel{background:var(--red)}.side{display:grid;gap:16px}.side-card{padding:18px}.side-title{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}.side-title h2{margin:0;text-transform:uppercase;font-size:22px}.count{display:grid;place-items:center;width:30px;height:30px;border-radius:50%;background:var(--red);font-weight:900}.selection-list{display:grid;gap:8px;min-height:60px}.pill{display:grid;grid-template-columns:1fr auto;gap:12px;align-items:center;border:1px solid var(--line);border-radius:8px;background:rgba(255,255,255,.035);padding:11px 12px;color:#fff;text-align:left}.pill small{display:block;color:#bbb;margin-top:4px}.pill button{border:0;background:transparent;color:#ddd;font-size:22px}.price-card{text-align:center}.price-label{color:#bbb;text-transform:uppercase;letter-spacing:1px}.price{margin:12px 0;color:var(--red2);font-size:clamp(30px,4vw,45px);font-weight:900}.desc{color:#ddd;line-height:1.45;margin:0}.promo-box{margin-top:12px;padding:12px;border:1px solid rgba(37,211,102,.24);border-radius:8px;background:rgba(37,211,102,.06);color:#d8ffe5;text-align:left}.promo-box b{color:#75ff9f}.promo-row{display:grid;grid-template-columns:1fr auto;gap:8px;margin-top:12px}.promo-row select,.promo-row button{min-width:0;border:1px solid var(--line);border-radius:8px;background:#090909;color:#fff;padding:11px;font-weight:900}.promo-row button{background:rgba(231,51,47,.22)}.field{display:grid;gap:7px;margin-top:12px}.field label{font-size:12px;text-transform:uppercase;color:#ddd;font-weight:900}.field input,.field textarea{width:100%;border:1px solid var(--line);border-radius:8px;background:#080808;color:#fff;padding:13px;outline:0}.field textarea{min-height:92px;resize:vertical}.zap{display:grid;place-items:center;margin-top:16px;min-height:64px;background:linear-gradient(180deg,#ee3c35,#bd1c18);border-color:rgba(255,255,255,.15);font-size:17px}.note{font-size:12px;color:#aaa;text-align:center;margin-top:12px;line-height:1.4}.regions{padding:18px;margin-top:22px}.regions-head{display:flex;justify-content:space-between;gap:12px;align-items:end;margin-bottom:14px}.regions-head h2{margin:0;text-transform:uppercase}.regions-head p{margin:0;color:#bbb}.region-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(118px,1fr));gap:10px}.region-card{min-height:88px;border:1px solid var(--line);border-radius:9px;background:radial-gradient(circle at 50% 18%,rgba(231,51,47,.22),transparent 34%),#080808;color:#fff;display:grid;align-content:end;padding:10px;text-align:left;font-size:11px;font-weight:900;text-transform:uppercase}.region-card.selected{border-color:#fff;box-shadow:0 0 18px rgba(231,51,47,.55);background:radial-gradient(circle at 50% 18%,rgba(231,51,47,.7),transparent 42%),#111}.foot{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-top:18px}.foot-card{padding:18px;color:#ddd}.foot-card b{display:block;color:#fff;text-transform:uppercase;margin-bottom:8px}.mobile-cta{display:none;position:fixed;left:12px;right:12px;bottom:12px;z-index:20;place-items:center;min-height:56px;border-radius:10px;background:var(--green);color:#06170b;text-decoration:none;font-weight:900;box-shadow:0 12px 36px #000}.tooltip{position:fixed;z-index:30;pointer-events:none;opacity:0;transform:translate(12px,12px);padding:8px 10px;border:1px solid var(--line);border-radius:8px;background:#050505;color:#fff;font-weight:900;box-shadow:0 10px 30px #000}.tooltip.show{opacity:1}@media(max-width:1180px){.hero{grid-template-columns:1fr}.side-card{position:static}.foot{grid-template-columns:1fr 1fr}.nav-links{display:none}}@media(max-width:720px){body{padding:0 10px 84px}.nav{height:64px}.brand span{font-size:12px}.top-zap{display:none}.heading{display:block}.tip{margin-top:12px;max-width:none}.stage{padding:14px}.map-box{height:590px}.region-grid{grid-template-columns:repeat(3,1fr)}.regions-head{display:block}.foot{grid-template-columns:1fr}.mobile-cta{display:grid}.promo-row{grid-template-columns:1fr}}
