",900,2800,"Área visível e sensível."),pe_planta:area("Pé (planta)",700,2200,"Área com alto desgaste."),dedos_pe:area("Dedos do pé",400,1100,"Melhor para marcas simples.")};
const hotspots={frente:[['cabeca','cabeca','Cabeça',46,5,8,9],['pescoco','pescoco','Pescoço',45,15,10,5],['ombro_esq_frente','ombros','Ombro esq.',30,18,14,8],['ombro_dir_frente','ombros','Ombro dir.',56,18,14,8],['peito_esq','peito','Peitoral esq.',38,24,12,13],['peito_dir','peito','Peitoral dir.',51,24,12,13],['abdomen','abdomen','Abdômen',43,37,14,18],['costela_esq','costela','Costela esq.',35,34,9,20],['costela_dir','costela','Costela dir.',57,34,9,20],['quadril','quadril','Quadril',41,54,18,9],['braco_esq_frente','braco_interno','Braço sup. interno esq.',23,26,11,21],['braco_dir_frente','braco_interno','Braço sup. interno dir.',66,26,11,21],['antebraco_esq_interno','antebraco_interno','Antebraço interno esq.',17,44,10,21],['antebraco_dir_interno','antebraco_interno','Antebraço interno dir.',73,44,10,21],['pulso_esq','pulso','Punho esq.',16,64,8,5],['pulso_dir','pulso','Punho dir.',76,64,8,5],['mao_esq_palma','mao_palma','Mão palma esq.',13,68,11,11],['mao_dir_palma','mao_palma','Mão palma dir.',77,68,11,11],['coxa_esq_frontal','coxa_frontal','Coxa frontal esq.',36,61,12,24],['coxa_dir_frontal','coxa_frontal','Coxa frontal dir.',52,61,12,24],['joelho_esq','joelho','Joelho esq.',38,84,10,7],['joelho_dir','joelho','Joelho dir.',53,84,10,7],['canela_esq','canela','Canela esq.',36,90,10,20],['canela_dir','canela','Canela dir.',54,90,10,20],['tornozelo_esq','tornozelo','Tornozelo esq.',35,109,11,5],['tornozelo_dir','tornozelo','Tornozelo dir.',55,109,11,5],['pe_esq_dorso','pe_dorso','Pé dorso esq.',33,113,14,7],['pe_dir_dorso','pe_dorso','Pé dorso dir.',54,113,14,7]],costas:[['cabeca_costas','cabeca','Cabeça',46,5,8,9],['nuca','pescoco','Nuca / pescoço',45,15,10,5],['ombro_esq_costas','ombros','Ombro esq.',30,18,14,8],['ombro_dir_costas','ombros','Ombro dir.',56,18,14,8],['costas_esq_alta','costas_superior','Costas superior esq.',37,23,13,16],['costas_dir_alta','costas_superior','Costas superior dir.',50,23,13,16],['costas_esq_media','costas_media','Costas média esq.',38,38,12,13],['costas_dir_media','costas_media','Costas média dir.',50,38,12,13],['costas_esq_baixa','costas_inferior','Costas inferior esq.',39,50,11,11],['costas_dir_baixa','costas_inferior','Costas inferior dir.',50,50,11,11],['lombar','lombar','Lombar',41,57,18,8],['braco_esq_costas','braco_externo','Braço sup. externo esq.',23,26,11,21],['braco_dir_costas','braco_externo','Braço sup. externo dir.',66,26,11,21],['antebraco_esq_externo','antebraco_externo','Antebraço externo esq.',17,44,10,21],['antebraco_dir_externo','antebraco_externo','Antebraço externo dir.',73,44,10,21],['mao_esq_dorso','mao_dorso','Mão dorso esq.',13,68,11,11],['mao_dir_dorso','mao_dorso','Mão dorso dir.',77,68,11,11],['gluteo_esq','gluteo','Glúteo esq.',38,62,12,12],['gluteo_dir','gluteo','Glúteo dir.',51,62,12,12],['coxa_esq_posterior','coxa_posterior','Coxa posterior esq.',36,72,12,22],['coxa_dir_posterior','coxa_posterior','Coxa posterior dir.',52,72,12,22],['joelho_esq_posterior','joelho_posterior','Joelho posterior esq.',38,93,10,6],['joelho_dir_posterior','joelho_posterior','Joelho posterior dir.',53,93,10,6],['panturrilha_esq','panturrilha','Panturrilha esq.',36,99,10,17],['panturrilha_dir','panturrilha','Panturrilha dir.',54,99,10,17],['tornozelo_esq_costas','tornozelo','Tornozelo esq.',35,115,11,5],['tornozelo_dir_costas','tornozelo','Tornozelo dir.',55,115,11,5],['pe_esq_planta','pe_planta','Pé planta esq.',33,119,14,7],['pe_dir_planta','pe_planta','Pé planta dir.',54,119,14,7]]};
const promotions=[promo('Braço completo externo esquerdo','Braço superior externo + antebraço externo + ombro',['ombro_esq_costas','braco_esq_costas','antebraco_esq_externo'],.88,'costas'),promo('Braço completo externo direito','Braço superior externo + antebraço externo + ombro',['ombro_dir_costas','braco_dir_costas','antebraco_dir_externo'],.88,'costas'),promo('Braço completo interno esquerdo','Braço superior interno + antebraço interno',['braco_esq_frente','antebraco_esq_interno'],.9,'frente'),promo('Braço completo interno direito','Braço superior interno + antebraço interno',['braco_dir_frente','antebraco_dir_interno'],.9,'frente'),promo('Peitoral completo','Peito esquerdo + peito direito',['peito_esq','peito_dir'],.9,'frente'),promo('Frontal completo','Peitoral + abdômen',['peito_esq','peito_dir','abdomen'],.85,'frente'),promo('Costas completa','Costas superior + média + inferior + lombar',['costas_esq_alta','costas_dir_alta','costas_esq_media','costas_dir_media','costas_esq_baixa','costas_dir_baixa','lombar'],.82,'costas'),promo('Mãos completas','Dorso das duas mãos',['mao_esq_dorso','mao_dir_dorso'],.9,'costas')];
const $=id=>document.getElementById(id), selected=new Map();let currentView='frente',activePromoTitle='';function money(v){return Number(v||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL',maximumFractionDigits:0})}function esc(v=''){return String(v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]))}function drawMaps(){draw('frontBox','frente',FRONT_IMG);draw('backBox','costas',BACK_IMG)}function draw(boxId,view,img){const box=$(boxId);box.innerHTML=`<img class="body-render" src="${img}" alt="Boneco 3D ${view}">`;hotspots[view].forEach(h=>{const b=document.createElement('button');b.type='button';b.className='hotspot';b.dataset.id=h[0];b.dataset.region=h[1];b.dataset.label=h[2];b.style.left=h[3]+'%';b.style.top=h[4]+'%';b.style.width=h[5]+'%';b.style.height=h[6]+'%';b.addEventListener('click',()=>selectPart(b));b.addEventListener('mousemove',e=>showTip(e,h[2]));b.addEventListener('mouseleave',hideTip);box.appendChild(b)})}function showTip(e,t){$('tooltip').textContent=t;$('tooltip').style.left=e.clientX+'px';$('tooltip').style.top=e.clientY+'px';$('tooltip').classList.add('show')}function hideTip(){$('tooltip').classList.remove('show')}function labelFromEl(el){return el.dataset.label||areas[el.dataset.region]?.titulo||el.dataset.region}function selectPart(el){activePromoTitle='';const item={id:el.dataset.id,region:el.dataset.region,label:labelFromEl(el)};selected.has(item.id)?selected.delete(item.id):selected.set(item.id,item);update()}function selectRegion(region){activePromoTitle='';const els=[...document.querySelectorAll(`.hotspot[data-region="${region}"]`)];const all=els.length&&els.every(e=>selected.has(e.dataset.id));els.forEach(e=>{const item={id:e.dataset.id,region:e.dataset.region,label:labelFromEl(e)};all?selected.delete(item.id):selected.set(item.id,item)});update()}function calculate(){if(!selected.size)return null;const total=[...selected.values()].reduce((a,i)=>{const d=areas[i.region]||{};return{min:a.min+Number(d.min||0),max:a.max+Number(d.max||0)}},{min:0,max:0});const p=getPromo();const disc=p?.desconto||1;return{originalMin:total.min,originalMax:total.max,min:Math.round(total.min*disc/50)*50,max:Math.round(total.max*disc/50)*50,promo:p,discountPercent:p?Math.round((1-disc)*100):0}}function getPromo(){return promotions.filter(p=>p.ids.every(id=>selected.has(id))).sort((a,b)=>a.desconto-b.desconto)[0]||null}function update(){document.querySelectorAll('.hotspot').forEach(e=>e.classList.toggle('selected',selected.has(e.dataset.id)));document.querySelectorAll('.region-card').forEach(c=>c.classList.toggle('selected',[...selected.values()].some(i=>i.region===c.dataset.region)));const items=[...selected.values()],est=calculate();$('count').innerText=items.length;$('selectionList').innerHTML=items.length?items.map(i=>{const d=areas[i.region]||{};return `<div class="pill"><span>${esc(i.label)}<small>${money(d.min)} - ${money(d.max)}</small></span><button type="button" data-remove="${i.id}">×</button></div>`}).join(''):'<div style="color:#aaa;line-height:1.4">Nenhuma região selecionada ainda.</div>';if(!est){$('preco').innerText='---';$('descricao').innerText='Clique em uma ou mais regiões para montar a estimativa inicial.';$('promoCurrent').style.display='none';renderPromos();links();return}$('preco').innerText=`${money(est.min)} - ${money(est.max)}`;$('descricao').innerText=est.promo?`${est.promo.titulo}: ${est.promo.descricao}`:(areas[items.at(-1).region]?.descricao||'Região selecionada.');renderPromos();links()}function links(){const est=calculate();const client=$('cliente').value.trim()||'Cliente ainda não informou';const idea=$('referenciaTexto').value.trim()||'Não descreveu ainda';const areaText=[...selected.values()].map(i=>i.label).join(', ')||'a definir';const price=est?`${money(est.min)} a ${money(est.max)}`:'Aguardando seleção de área';const promoLine=est?.promo?`Promoção: ${est.promo.titulo}`:'Promoção: não selecionada';const msg=['Olá! Quero um orçamento de tatuagem.',`Nome: ${client}`,`Área escolhida: ${areaText}`,promoLine,`Referência/ideia: ${idea}`,'Vou enviar a imagem de referência aqui na conversa, se tiver.',`Pré-orçamento: ${price}`,'Sei que o valor final depende de avaliação.'].join('\n');const href=`https://wa.me/${DEFAULT_CONFIG.whatsapp}?text=${encodeURIComponent(msg)}&utm_source=orcamento_3d&utm_medium=site&utm_campaign=orcamento`;['zap','mobileCta','topZap'].forEach(id=>$(id).href=href)}function renderPromos(){const active=promotions;$('promoSelect').innerHTML='<option value="">Selecionar promoção</option>'+active.map((p,i)=>`<option value="${i}">${p.titulo} · ${Math.round((1-p.desconto)*100)}% OFF</option>`).join('');const p=active.find(x=>x.titulo===activePromoTitle)||getPromo();const box=$('promoCurrent');if(p){$('promoSelect').value=String(active.indexOf(p));const est=calculate();if(est?.promo){box.style.display='block';box.innerHTML=`<b>Promoção aplicada!</b> <span style="float:right;background:rgba(37,211,102,.18);padding:4px 9px;border-radius:999px">${est.discountPercent}% OFF</span><br><span>${esc(p.descricao)}</span>`}else box.style.display='none'}else box.style.display='none'}function renderRegionGrid(){$('regionGrid').innerHTML=Object.keys(areas).map(k=>`<button type="button" class="region-card" data-region="${k}">${esc(areas[k].titulo)}</button>`).join('');document.querySelectorAll('.region-card').forEach(b=>b.addEventListener('click',()=>selectRegion(b.dataset.region)))}function setView(v){currentView=v==='costas'?'costas':'frente';document.querySelectorAll('[data-view]').forEach(b=>b.classList.toggle('active',b.dataset.view===currentView));$('frontBox').classList.toggle('hidden',currentView!=='frente');$('backBox').classList.toggle('hidden',currentView!=='costas')}$('selectionList').addEventListener('click',e=>{const b=e.target.closest('[data-remove]');if(!b)return;selected.delete(b.dataset.remove);activePromoTitle='';update()});$('applyPromo').addEventListener('click',()=>{const p=promotions[Number($('promoSelect').value)];if(!p)return;selected.clear();activePromoTitle=p.titulo;setView(p.view);p.ids.forEach(id=>{const el=document.querySelector(`[data-id="${id}"]`);if(el)selected.set(id,{id,region:el.dataset.region,label:labelFromEl(el)})});update()});document.querySelectorAll('[data-view]').forEach(b=>b.addEventListener('click',()=>setView(b.dataset.view)));['cliente','referenciaTexto'].forEach(id=>$(id).addEventListener('input',links));$('zap').addEventListener('click',()=>{window.dataLayer=window.dataLayer||[];window.dataLayer.push({event:'whatsapp_click',areas:[...selected.values()].map(i=>i.label).join(', ')})});drawMaps();renderRegionGrid();renderPromos();update();
</script>
</body>
</html>